// Валидация запроса от Django.
// Ожидаем JSON-body: { message: '...', agent: 'chat|math|rag|sql|router|prompt-engineer', session_id?: '...' }
// agent опциональный — default 'chat'
// session_id опциональный — генерируем если нет

const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();
const agent = (body.agent || 'chat').toString().trim().toLowerCase();

if (!message) {
  return [{ json: { valid: 0, error: 'Поле message обязательно' } }];
}

if (message.length > 100000) {
  return [{ json: { valid: 0, error: 'Слишком длинный message (>100000 символов)' } }];
}

// Whitelist agent-имён (соответствуют webhook-path'ам существующих агентов)
const ALLOWED_AGENTS = ['chat', 'math', 'rag', 'sql', 'router', 'prompt-engineer'];
if (!ALLOWED_AGENTS.includes(agent)) {
  return [{ json: { valid: 0, error: 'Неизвестный agent: "' + agent + '". Доступны: ' + ALLOWED_AGENTS.join(', ') } }];
}

// session_id: либо из body, либо генерируем.
// Каждый запрос без session_id = новый диалог (без истории).
// Если Django хочет вести непрерывный диалог — пусть передаёт session_id явно.
let session_id = (body.session_id || '').toString().trim();
if (!session_id) {
  const ts = Date.now();
  const rand = Math.random().toString(36).slice(2, 8);
  session_id = `django_${ts}_${rand}`;
}

// Защита от инъекций (то же правило что в других агентах)
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{ json: { valid: 0, error: 'session_id содержит недопустимые символы или длина <3' } }];
}

return [{ json: { valid: 1, message, agent, session_id } }];

// Собираем callback-body для Django.
// Источник «оригинальных» полей — нода «Валидация» (там нормализованные значения).
// Результат вызова агента — текущий $json (приходит от ноды «Вызов агента»).

const src = $('Валидация').first().json;
const raw = $input.first().json || {};

// Парсим ответ агента. Все наши агенты отвечают полем `response`.
// Если ошибка — поля `error` или request не дошёл.
let response = '';
let ok = true;
let error = null;

if (raw.error) {
  ok = false;
  error = typeof raw.error === 'string' ? raw.error : JSON.stringify(raw.error);
} else if (typeof raw.response === 'string') {
  response = raw.response;
} else if (raw.response != null) {
  response = String(raw.response);
} else {
  ok = false;
  error = 'Агент не вернул поле response';
}

return [{ json: {
  ok: ok,
  agent: src.agent,
  message: src.message,
  session_id: src.session_id,
  response: response,
  error: error,
  timestamp: new Date().toISOString()
}}];
